const mongoose = require('mongoose');

async function queryBuilder(filter, projection, sort) {
    try {
        // Connect to MongoDB (ensure you have the connection string and model defined)
        await mongoose.connect('mongodb://localhost:27017/yourDatabase', { useNewUrlParser: true, useUnifiedTopology: true });

        const YourModel = mongoose.model('YourCollectionName', new mongoose.Schema({ /* your schema definition */ }));

        // Build the query
        const query = YourModel.find(filter);

        // Apply projection if provided
        if (projection) {
            query.select(projection);
        }

        // Apply sort criteria if provided
        if (sort) {
            query.sort(sort);
        }

        // Execute the query
        const results = await query.exec();

        return results;
    } catch (error) {
        console.error('Error executing query:', error);
        throw error;
    }
}

